        public MyArrayList(int capacity) {
            data = new Object[capacity];
            size = 0;
        }

        public void add(Object o) {
            if (size == data.length) {
                Object[] nd = new Object[data.length * 2];
                System.arraycopy(data, 0, nd, 0, data.length);
                data = nd;
            }
            data[size++] = o;
        }

        public Object get(int index) {
            if (index < 0 || index >= size) throw new IndexOutOfBoundsException("index=" + index);
            return data[index];
        }

        public boolean contains(Object o) {
            for (int i = 0; i < size; i++) {
                Object v = data[i];
                if (v == null) {
                    if (o == null) return true;
                } else if (v.equals(o)) return true;
            }
            return false;
        }

        public int size() {
            return size;
        }
    }

    // Simple HashMap-like implementation using separate chaining and resizing
    public static class MyHashMap {
        static class Node {
            final Object key;
            Object value;
            Node next;

            Node(Object key, Object value, Node next) {
                this.key = key;
                this.value = value;
                this.next = next;
            }
        }

        private Node[] table;
        private int size;
        private int threshold;
        private final float loadFactor;

        public MyHashMap() {
            this(16, 0.75f);
        }

        public MyHashMap(int capacity, float loadFactor) {
            this.table = new Node[capacity];
            this.loadFactor = loadFactor;
            this.threshold = (int) (capacity * loadFactor);
            this.size = 0;
        }

        private int indexFor(Object key, int length) {
            int h = (key == null) ? 0 : key.hashCode();
            h ^= (h >>> 16);
            return (h & 0x7fffffff) % length;
        }

        public void put(Object key, Object value) {
            int idx = indexFor(key, table.length);
            for (Node e = table[idx]; e != null; e = e.next) {
                if (key == e.key || (key != null && key.equals(e.key))) {
                    e.value = value;
                    return;
                }
            }
            Node n = new Node(key, value, table[idx]);
            table[idx] = n;
            size++;
            if (size > threshold) resize(table.length * 2);
        }

        public Object get(Object key) {
            int idx = indexFor(key, table.length);
            for (Node e = table[idx]; e != null; e = e.next) {
                if (key == e.key || (key != null && key.equals(e.key))) return e.value;
            }
            return null;
        }

        public boolean containsKey(Object key) {
            int idx = indexFor(key, table.length);
            for (Node e = table[idx]; e != null; e = e.next) {
                if (key == e.key || (key != null && key.equals(e.key))) return true;
            }
            return false;
        }

        private void resize(int newCapacity) {
            Node[] newTable = new Node[newCapacity];
            for (int i = 0; i < table.length; i++) {
                Node e = table[i];
                while (e != null) {
                    Node next = e.next;
                    int idx = indexFor(e.key, newCapacity);
                    e.next = newTable[idx];
                    newTable[idx] = e;
                    e = next;
                }
            }
            table = newTable;
            threshold = (int) (newCapacity * loadFactor);
        }

        public int size() {
            return size;
        }
    }

